// IsSilent 回傳是否為「完全靜默」模式（debug_level=none）
func (c *HypConfig) IsSilent() bool {
	return c != nil && c.DebugLevel == DebugLevelNone
}

// IsDebug 回傳是否需要印出 debug 等級訊息（debug_level=debug 時為 true）
func (c *HypConfig) IsDebug() bool {
	return c != nil && c.DebugLevel == DebugLevelDebug
}

